price.js_extraction:
// Strategy 1: Look for common SFCC/React price patterns in rendered DOM
// Try multiple selectors since exact classes are minified/hashed:
[...document.querySelectorAll('[class*="price"], [class*="Price"], [class*="cost"], [data-price], [itemprop="price"]]')].map(el => el.textContent.trim()).filter(t => /^[£€$]/.test(t))

// Strategy 2: Look for £ symbol near product area
[...document.querySelectorAll('span, div')].filter(el => /£\s*\d+/.test(el.textContent)).map(el => el.textContent.trim()).slice(0, 5)

// Strategy 3: Search all text nodes for price patterns
Array.from(document.querySelectorAll('*')).flatMap(el => Array.from(el.childNodes).filter(n => n.nodeType === 3 && /£\s*\d+[.,]?\d{0,2}/.test(n.textContent)).map(n => n.textContent.trim()))

availability.js_extraction:
// Strategy 1: Check JSON-LD offers (may be empty)
// Strategy 2: Look for availability-related text in DOM
[...document.querySelectorAll('[class*="avail"], [class*="stock"], [class*="inventory"], [data-availability], [itemprop="availability"]')].map(el => el.textContent.trim())

// Strategy 3: Check for 'Out of Stock', 'In Stock' text
const allText = document.body.innerText;
if (/out\s+of\s+stock/i.test(allText)) 'Out of Stock';
else if (/in\s+stock|available/i.test(allText)) 'In Stock';
else 'Unknown'

variants.js_extraction:
// Color variants — look for color swatch buttons or dropdowns
[...document.querySelectorAll('[class*="color"], [class*="swatch"], [class*="variant"]')].filter(el => el.tagName === 'BUTTON' || el.tagName === 'A' || el.tagName === 'INPUT').map(el => ({ value: el.getAttribute('data-value') || el.getAttribute('aria-label') || el.textContent.trim(), type: el.getAttribute('data-attr') || 'unknown' }))

// Size variants — look for size selector
[...document.querySelectorAll('[class*="size"], [class*="fit"]')].filter(el => el.tagName === 'BUTTON' || el.tagName === 'A' || el.tagName === 'OPTION' || el.tagName === 'INPUT').map(el => ({ value: el.getAttribute('data-value') || el.textContent.trim(), available: !el.classList.contains('unavailable') && !el.disabled }))

recommended_extraction_code.json_ld_extractor:
function extractJsonLd(page) {
  const scripts = document.querySelectorAll('script[type="application/ld+json"]');
  let product = null;
  let breadcrumbs = null;
  for (const script of scripts) {
    try {
      const data = JSON.parse(script.textContent);
      const items = Array.isArray(data) ? data : [data];
      for (const item of items) {
        if (item['@type'] === 'Product') product = item;
        if (item['@type'] === 'BreadcrumbList') breadcrumbs = item;
      }
    } catch(e) {}
  }
  return { product, breadcrumbs };
}

recommended_extraction_code.price_extractor:
function extractPrice(doc) {
  // Try to find price by looking for £ symbol in text content
  const prices = [];
  const allElements = doc.querySelectorAll('span, div, p');
  for (const el of allElements) {
    const text = el.textContent.trim();
    const match = text.match(/£\s*([0-9]+[.,]?[0-9]{0,2})/);
    if (match) {
      prices.push({ price: match[0], context: text.substring(0, 50), element: el.tagName + '.' + el.className });
    }
  }
  // Filter to likely product prices (not shipping, not footer)
  return prices.filter(p => !/shipp|deliver|return|footer/i.test(p.context));
}

recommended_extraction_code.availability_extractor:
function extractAvailability(doc) {
  const btn = doc.querySelector('[class*="add"]'); 
  // Look for 'Add to Bag' or similar button — if disabled or absent, likely OOS
  const text = doc.body.innerText;
  if (/out\s+of\s+stock/i.test(text)) return 'Out of Stock';
  if (/in\s+stock/i.test(text)) return 'In Stock';
  return 'Unknown';
}
